{"title": "Queue", "summary": "A linear FIFO (First-In, First-Out) data structure where elements are inserted at the rear and removed from the front. Used extensively in CPU scheduling, I/O buffering, and BFS traversal.", "key_points": ["FIFO order: first element in is first element out.", "Core operations: enqueue (rear), dequeue (front). Both O(1).", "Overflow: enqueue on full queue. Underflow: dequeue on empty queue.", "Variants: Circular Queue, Priority Queue, Deque.", "Used in BFS, OS scheduling, print spooling, message buffers."], "code": {"c": "#define MAX 100
int queue[MAX], front = -1, rear = -1;

void enqueue(int val) {
    if (rear == MAX - 1) { printf("Overflow\n"); return; }
    if (front == -1) front = 0;
    queue[++rear] = val;
}

int dequeue() {
    if (front == -1 || front > rear) { printf("Underflow\n"); return -1; }
    return queue[front++];
}

void display() {
    for (int i = front; i <= rear; i++)
        printf("%d ", queue[i]);
}", "python": "from collections import deque

class Queue:
    def __init__(self):
        self.q = deque()

    def enqueue(self, val):
        self.q.append(val)

    def dequeue(self):
        if not self.q:
            raise IndexError('Underflow')
        return self.q.popleft()

    def is_empty(self):
        return len(self.q) == 0

q = Queue()
q.enqueue(10)
q.enqueue(20)
print(q.dequeue())  # 10", "cpp": "#include<queue>
