# Max-heap (negate values)
h2 = []
heapq.heappush(h2, -10)
heapq.heappush(h2, -5)
print(-heapq.heappop(h2))  # 10 (max)"}, "execution_steps": ["1. Represent heap as 1D array (parent at i, left child at 2i+1, right at 2i+2).", "2. Insert: append element at end, sift up by swapping with parent while larger.", "3. Extract-max: swap root with last, remove last, sift down from root.", "4. Sift down: find largest among node and children, swap if needed, recurse.", "5. Build heap: run heapify bottom-up from n/2-1 to 0."], "variants": ["Priority Queue", "Min-Heap", "Fibonacci Heap"], "visual_hooks": ["animate_sift_up(index)", "animate_sift_down(root, n)", "highlight_heap_root()"], "reasoning_map": {"problem": "Need O(log n) access to the minimum or maximum element dynamically.", "solution": "Maintain a complete binary tree with the heap property.", "tradeoffs": "Not sorted fully; only guarantees root is extremum. Random access is O(n)."}}

{"title": "Merge Sort", "summary": "A stable divide-and-conquer sorting algorithm that recursively splits an array in half, sorts each half, then merges them in sorted order. Guarantees O(n log n) in all cases.", "key_points": ["Stable sort — equal elements maintain original relative order.", "O(n log n) time complexity in all cases (best, worst, average).", "O(n) extra space needed for merging.", "Preferred for sorting linked lists (no random access needed).", "Base of TimSort used in Python's built-in sort."], "code": {"c": "void merge(int arr[], int l, int m, int r) {
    int n1 = m-l+1, n2 = r-m;
    int L[n1], R[n2];
    for(int i=0;i<n1;i++) L[i]=arr[l+i];
    for(int i=0;i<n2;i++) R[i]=arr[m+1+i];
    int i=0,j=0,k=l;
    while(i<n1&&j<n2) arr[k++]=(L[i]<=R[j])?L[i++]:R[j++];
    while(i<n1) arr[k++]=L[i++];
    while(j<n2) arr[k++]=R[j++];
}
void mergeSort(int arr[], int l, int r) {
    if(l<r) { int m=(l+r)/2; mergeSort(arr,l,m); mergeSort(arr,m+1,r); merge(arr,l,m,r); }
}", "python": "def merge_sort(arr):
    if len(arr) <= 1:
        return arr
    mid = len(arr) // 2
    left = merge_sort(arr[:mid])
    right = merge_sort(arr[mid:])
    return merge(left, right)

def merge(left, right):
    result = []
    i = j = 0
    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i]); i += 1
        else:
            result.append(right[j]); j += 1
    result.extend(left[i:])
    result.extend(right[j:])
    return result

print(merge_sort([38, 27, 43, 3, 9]))  # [3, 9, 27, 38, 43]"}, "execution_steps": ["1. Base case: if array has 0 or 1 element, return as-is.", "2. Split: divide array at midpoint into left and right halves.", "3. Recurse: apply merge sort to left half and right half.", "4. Merge: combine two sorted halves into one sorted array by comparing element-by-element.", "5. Return the merged sorted array."], "variants": ["Quick Sort", "Heap Sort", "TimSort"], "visual_hooks": ["animate_split(mid)", "animate_merge(left, right)", "show_recursion_depth(depth)"], "reasoning_map": {"problem": "Need guaranteed O(n log n) stable sort for large datasets.", "solution": "Divide-and-conquer: split into trivially sortable pieces then merge.", "tradeoffs": "Guaranteed performance but requires O(n) extra memory; Quick Sort is faster in practice for in-memory arrays."}}
